274	// SubscribeChangeEvents streams change events for the given project ID.
275	func (c *Client) SubscribeChangeEvents(ctx context.Context, projectID string) (<-chan ChangeEvent, error) {
276		sub, ok := c.transport.(SubscriptionTransport)
277		if !ok {
278			return nil, fmt.Errorf("axon: subscription transport not configured")
279		}
280	
281		raw, err := sub.Subscribe(ctx, changeEventsSubscription, map[string]any{"projectID": projectID})
282		if err != nil {
283			return nil, err
284		}
285	
286		out := make(chan ChangeEvent)
287		go func() {
288			defer close(out)
289			for payload := range raw {
290				var env changeEventsEnvelope
291				if err := json.Unmarshal(payload, &env); err != nil {
292					continue
293				}
294				if env.Data.ChangeEvents == nil {
295					continue
296				}
297				select {
298				case out <- *env.Data.ChangeEvents:
299				case <-ctx.Done():
300					return
301				}
302			}
303		}()
304	
305		return out, nil
306	}
